import mysql.connector

def import_data(file_path, table_name):
    connection = mysql.connector.connect(
        host='localhost',
        user='your_username',
        password='your_password',
        database='your_database',
        allow_local_infile=True
    )
    
    cursor = connection.cursor()
    
    load_data_query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {}".format(file_path, table_name)
    
    try:
        cursor.execute(load_data_query)
        connection.commit()
        print("Data imported successfully.")
    except mysql.connector.Error as err:
        print("Error: {}".format(err))
    finally:
        cursor.close()
        connection.close()

if __name__ == "__main__":
    file_path = input("Enter the file path for import: ")
    table_name = input("Enter the table name for import: ")
    import_data(file_path, table_name)